Totally untested, but something like this should work.

```
ctr=$(buildah from golang:1.7.3)
buildah config --workdir=/go/src/github.com/alexellis/href-counter/ ${ctr}
buildah run ${ctr} go get -d -v golang.org/x/net/html  
buildah copy ${ctr} app.go .
buildah run ${ctr} CGO_ENABLED=0 GOOS=linux go build -a -installsuffix cgo -o app .
mnt=$(buildah mount ${ctr})

ctr1=$(FROM alpine:latest)
buildah run ${ctr1} apk --no-cache add ca-certificates
buildah config --workdir=/root/ ${ctr1}
mnt1=$(buildah mount {ctr1})
cp ${mnt}/go/src/github.com/alexellis/href-counter/app ${mnt1}
buildah config --cmd='["./app"]' ${ctr1}
buildah umount ${ctr}
buildah rm -f ${ctr}
buildah commit ${ctr1} MYIMAGENAME
buildah umount ${ctr1}
buildah rm -f ${ctr1}
```
